SET NAMES utf8mb4;
USE `@DB@`;
ALTER TABLE `sys_auth` MODIFY `auth_code` varchar(64) CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL;
DELETE FROM `sys_ra`   WHERE `auth_id` IN (SELECT auth_id FROM (SELECT auth_id FROM `sys_auth` WHERE p_auth_id=26000 OR auth_id=26000) x);
DELETE FROM `sys_auth` WHERE `auth_id`=26000 OR `p_auth_id`=26000;
